func solve(grid [][]int64, k int64) int64 {
    m := len(grid)
    n := len(grid[0])
    dp := make([][][]int64, m)
    for i := range dp {
        dp[i] = make([][]int64, n)
        for j := range dp[i] {
            dp[i][j] = make([]int64, k+1)
            for t := range dp[i][j] {
                dp[i][j][t] = int64(math.MaxInt64)
            }
        }
    }
    dp[0][0][0] = 0

    for i := 0; i < m; i++ {
        for j := 0; j < n; j++ {
            for t := 0; t <= k; t++ {
                if dp[i][j][t] == int64(math.MaxInt64) {
                    continue
                }

                // Regular move: right
                if j+1 < n {
                    cost := grid[i][j+1]
                    if dp[i][j+1][t] > dp[i][j][t]+cost {
                        dp[i][j+1][t] = dp[i][j][t] + cost
                    }
                }

                // Regular move: down
                if i+1 < m {
                    cost := grid[i+1][j]
                    if dp[i+1][j][t] > dp[i][j][t]+cost {
                        dp[i+1][j][t] = dp[i][j][t] + cost
                    }
                }

                // Teleportation
                if t < k {
                    for x := 0; x < m; x++ {
                        for y := 0; y < n; y++ {
                            if grid[x][y] <= grid[i][j] {
                                if dp[x][y][t+1] > dp[i][j][t] {
                                    dp[x][y][t+1] = dp[i][j][t]
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    minCost := int64(math.MaxInt64)
    for t := 0; t <= k; t++ {
        if dp[m-1][n-1][t] < minCost {
            minCost = dp[m-1][n-1][t]
        }
    }

    return minCost
}
